void OnKeyDown(UINT nChar)

{

	// Add your keyboard handler code here

   Group.Sound_Holder.Stop(0);

   SetTimer(0);



      // Odgrywane jest demo - nic nie mozna robic na klawiaturze

   if( akcja == 3 )

      return;



   if( nChar==keyDown ) return;

   keyDown = nChar;



   switch(nChar)

   {                



      case 122: // q - beben1

      case 90:

         Muzyka( 0 );

         break;



      case 120:  // w - beben2

      case 88:

         Muzyka( 1 );

         break;    



      case 99:  // e - beben3

      case 67:

         Muzyka( 2 );

         break;                                              



      case 118: // r - bebenek

      case 86:

         Muzyka( 3 );

         break;



      case 109: // t - tamtam1

      case 77:

         Muzyka( 4 );

         break;



      case 44: // y - tamtam2

         Muzyka( 5 );

         break;



      case 46: // u - talerz

         Muzyka( 6 );

         break;



      case 47: // i - marakas

         Muzyka( 7 );

         break;



      case 32:  // tab - dzwonek

         Muzyka( 8 );

         break;

   }

}







void OnKeyUp(UINT nChar)

{

        //Add your command handler code here

   keyDown = 0;

}



///////////////////////////////////////////////////////////////////////

//   nrRuchu - wskazuje ktory ruch bedzie wykonany

//      

//

// 0 - beben 1

// 1 - beben 2

// 2 - beben 3

// 3 - bebenek

// 4 - tamtam1

// 5 - tamtam2

// 6 - talerz

// 7 - marakas

// 8 - dzwonek

//

void Muzyka( int nrRuchu )



{

   if(m_demo)

      Sound_Holder.PlayDSoundEx(nrRuchu,-10000,0,0);

   else

      Sound_Holder.PlayDSound( nrRuchu );



      // Jelis dzwiek dotyczy skrzypiec to 

      // - nalezy ruszyc smyczkiem w przeciwym kierunku

   switch( nrRuchu )

   {

      case 0:   // beben 1

         Bitmap_Holder.HideBitmap( 1 );

         Bitmap_Holder.HideBitmap( 2 );



         Bitmap_Holder.ShowBitmap( nrRuchu );

         break;



      case 1:   // beben 2

         Bitmap_Holder.HideBitmap( 0 );

         Bitmap_Holder.HideBitmap( 2 );



         Bitmap_Holder.ShowBitmap( nrRuchu );

         break;



      case 2:   // beben 3

         Bitmap_Holder.HideBitmap( 1 );

         Bitmap_Holder.HideBitmap( 0 );



         Bitmap_Holder.ShowBitmap( nrRuchu );

         break;



      case 3:   // bebenek

      case 4:   // tamtam1

      case 5:   // tamtam2

      case 6:

         Bitmap_Holder.ShowBitmap( nrRuchu );

         break;



      case 7:

         Sprite_Holder.ChangePhase( 0, 1 );

         break;



      case 8:

         Sprite_Holder.ChangePhase( 1, 1 );

         break;



   }



}







